mapper.select:

SELECT
	B.DEPLOY_SYS_URL AS deployUrl
FROM TBINTRFCDEPLOYSYSDT A inner join TBDEPOLYSYSBS B on A.DEPLOY_SYS_CD = B.DEPLOY_SYS_CD
WHERE A.INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
AND A.DEPLOY_SYS_CD = #{deploySystem, jdbcType = VARCHAR}

mapper.insert:
	INSERT INTO TBINTRFCDEPLOYSYSDT (
		 INTRFC_ID		
		,DEPLOY_SYS_CD		
		,DEPLOY_SYS_SEQ		
		,DEPLOY_RESULT_CD		
	) VALUES (
		 #{intrfcId, jdbcType = VARCHAR}
 		,#{deploySysCd, jdbcType = VARCHAR}
 		,#{deploySysSeq, jdbcType = NUMERIC}
 		,#{deployResultCd, jdbcType = VARCHAR}
  	)

mapper.update:
	UPDATE TBINTRFCDEPLOYSYSDT 
	SET
 		DEPLOY_SYS_CD = #{deploySysCd, jdbcType = VARCHAR}		
  		,DEPLOY_SYS_SEQ = #{deploySysSeq, jdbcType = NUMERIC}		
  		,DEPLOY_RESULT_CD = #{deployResultCd, jdbcType = VARCHAR}		
   	WHERE INTRFC_ID = #{intrfcId, jdbcType = VARCHAR}
